import { describe, expect, it } from '@a0n/gnosis/test';
import { InMemoryNonceReplayStore } from './tee-attestation';
import {
  createCertifiedRuntimeAttestation,
  createReactorHandleGrant,
  hashAeonReactorPolicy,
  verifyCertifiedRuntimeAttestation,
  verifyReactorHandleGrant,
  type AeonReactorPolicy,
  type ReactorHandleGrantClaims,
} from './reactor-attestation';

const ECDSA_SIGNING_ALGORITHM: EcKeyImportParams = {
  name: 'ECDSA',
  namedCurve: 'P-256',
};
const ECDSA_SIGNATURE_ALGORITHM: EcdsaParams = {
  name: 'ECDSA',
  hash: 'SHA-256',
};

async function generateSigningMaterial(): Promise<{
  privateKey: JsonWebKey;
  publicKey: JsonWebKey;
}> {
  const keyPair = await crypto.subtle.generateKey(
    {
      name: 'ECDSA',
      namedCurve: 'P-256',
    },
    true,
    ['sign', 'verify']
  );

  const privateKey = await crypto.subtle.exportKey('jwk', keyPair.privateKey);
  const publicKey = await crypto.subtle.exportKey('jwk', keyPair.publicKey);

  return {
    privateKey,
    publicKey,
  };
}

function stableStringify(value: unknown): string {
  if (value === null || value === undefined) {
    return 'null';
  }

  if (typeof value === 'string') {
    return JSON.stringify(value);
  }

  if (typeof value === 'number') {
    return Number.isFinite(value) ? String(value) : 'null';
  }

  if (typeof value === 'boolean') {
    return value ? 'true' : 'false';
  }

  if (typeof value === 'bigint') {
    return JSON.stringify(value.toString(10));
  }

  if (Array.isArray(value)) {
    return `[${value.map((item) => stableStringify(item)).join(',')}]`;
  }

  if (typeof value === 'object') {
    const record = value as Record<string, unknown>;
    const entries = Object.entries(record)
      .filter(([, entryValue]) => {
        const entryType = typeof entryValue;
        return (
          entryType !== 'undefined' &&
          entryType !== 'function' &&
          entryType !== 'symbol'
        );
      })
      .sort(([leftKey], [rightKey]) => leftKey.localeCompare(rightKey));

    return `{${entries
      .map(
        ([key, entryValue]) =>
          `${JSON.stringify(key)}:${stableStringify(entryValue)}`
      )
      .join(',')}}`;
  }

  return 'null';
}

function toArrayBuffer(bytes: Uint8Array): ArrayBuffer {
  return bytes.buffer.slice(
    bytes.byteOffset,
    bytes.byteOffset + bytes.byteLength
  ) as ArrayBuffer;
}

async function signClaims(
  claims: unknown,
  privateKey: JsonWebKey
): Promise<string> {
  const key = await crypto.subtle.importKey(
    'jwk',
    privateKey,
    ECDSA_SIGNING_ALGORITHM,
    false,
    ['sign']
  );
  const signature = await crypto.subtle.sign(
    ECDSA_SIGNATURE_ALGORITHM,
    key,
    toArrayBuffer(new TextEncoder().encode(stableStringify(claims)))
  );
  return Buffer.from(new Uint8Array(signature))
    .toString('base64')
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/u, '');
}

function buildPolicy(): AeonReactorPolicy {
  return {
    version: 'aeon_reactor_v1',
    runtime: 'gnosis-uring',
    defaultEffect: 'deny',
    rules: [
      {
        operation: 'request.read',
        effect: 'allow',
        ucanCapability: 'aeon/request.read',
        resource: 'aeon://request/*',
      },
      {
        operation: 'response.write',
        effect: 'allow',
        ucanCapability: 'aeon/response.write',
        resource: 'aeon://response/*',
      },
      {
        operation: 'stream.open',
        effect: 'allow',
        ucanCapability: 'aeon/stream.open',
        hostCapability: 'net.tcp.client',
        resource: 'aeon://stream/outbound/*',
      },
      {
        operation: 'vfs.read',
        effect: 'allow',
        ucanCapability: 'aeon/vfs.read',
        resource: 'aeon://vfs/*',
      },
    ],
  };
}

describe('reactor-attestation', () => {
  it('creates and verifies a certified runtime attestation bound to reactor policy and tee report data', async () => {
    const signingMaterial = await generateSigningMaterial();
    const policy = buildPolicy();
    const nowMs = Date.now();
    const attestation = await createCertifiedRuntimeAttestation({
      claims: {
        runtime: 'gnosis-uring',
        audience: 'did:key:z6MkAudience',
        subject: 'did:key:z6MkGuest',
        buildHash: 'build-hash-v1',
        bundleDigest: 'bundle-digest-v1',
        lawDigest: 'law-digest-v1',
        hostCapabilities: ['net.tcp.client', 'auth.ucan', 'fs.local'],
        admittedOperations: [
          'request.read',
          'response.write',
          'stream.open',
          'vfs.read',
        ],
        surfaces: ['http', 'raw-flow', 'wasm'],
        projectDigest: 'project-digest-v1',
        ucanIssuer: 'did:key:z6MkIssuer',
        nonce: `nonce-${crypto.randomUUID()}`,
        issuedAt: nowMs - 1_000,
        expiresAt: nowMs + 60_000,
        policy,
        tee: {
          provider: 'mock',
          measurement: 'TEE-MEASUREMENT-1',
          tcbVersion: '1.4.0',
          documentHash: 'document-hash-v1',
        },
      },
      privateKey: signingMaterial.privateKey,
      publicKey: signingMaterial.publicKey,
      keyId: 'runtime-dev',
    });

    const verified = await verifyCertifiedRuntimeAttestation(attestation, {
      nowMs,
      trustedKeyById: {
        'runtime-dev': signingMaterial.publicKey,
      },
      trustedProviders: ['mock'],
      trustedMeasurements: ['TEE-MEASUREMENT-1'],
      expectedPolicy: policy,
      expectedRuntime: 'gnosis-uring',
      expectedAudience: 'did:key:z6MkAudience',
      expectedSubject: 'did:key:z6MkGuest',
      expectedBuildHash: 'build-hash-v1',
      expectedBundleDigest: 'bundle-digest-v1',
      expectedLawDigest: 'law-digest-v1',
      expectedProjectDigest: 'project-digest-v1',
      expectedUcanIssuer: 'did:key:z6MkIssuer',
      expectedSurfaces: ['http', 'raw-flow', 'wasm'],
      expectedAdmittedOperations: [
        'request.read',
        'response.write',
        'stream.open',
        'vfs.read',
      ],
      minTcbVersion: '1.3.0',
    });

    expect(verified.valid).toBe(true);
    expect(verified.bindingHash).toBe(attestation.claims.bindingHash);
    expect(attestation.claims.tee.reportDataHash).toBe(
      attestation.claims.bindingHash
    );
  });

  it('rejects runtime attestation when tee report data no longer matches runtime binding', async () => {
    const signingMaterial = await generateSigningMaterial();
    const policy = buildPolicy();
    const nowMs = Date.now();
    const attestation = await createCertifiedRuntimeAttestation({
      claims: {
        runtime: 'gnosis-uring',
        audience: 'did:key:z6MkAudience',
        buildHash: 'build-hash-v2',
        hostCapabilities: ['auth.ucan'],
        admittedOperations: ['request.read'],
        surfaces: ['wasm'],
        nonce: `nonce-${crypto.randomUUID()}`,
        issuedAt: nowMs - 1_000,
        expiresAt: nowMs + 60_000,
        policy,
        tee: {
          provider: 'mock',
          measurement: 'TEE-MEASUREMENT-2',
          tcbVersion: '1.0.0',
        },
      },
      privateKey: signingMaterial.privateKey,
      publicKey: signingMaterial.publicKey,
    });

    const tampered = {
      ...attestation,
      claims: {
        ...attestation.claims,
        tee: {
          ...attestation.claims.tee,
          reportDataHash: 'not-the-binding-hash',
        },
      },
    };
    tampered.signature = await signClaims(
      tampered.claims,
      signingMaterial.privateKey
    );

    const verified = await verifyCertifiedRuntimeAttestation(tampered, {
      nowMs,
      trustedPublicKeys: [signingMaterial.publicKey],
      trustedMeasurements: ['TEE-MEASUREMENT-2'],
      expectedPolicyHash: await hashAeonReactorPolicy(policy),
    });

    expect(verified.valid).toBe(false);
    expect(verified.reason).toContain('reportDataHash');
  });

  it('detects runtime attestation nonce replay and verifies reactor handle grants bound to the runtime', async () => {
    const signingMaterial = await generateSigningMaterial();
    const policy = buildPolicy();
    const nowMs = Date.now();
    const nonceStore = new InMemoryNonceReplayStore();
    const runtime = await createCertifiedRuntimeAttestation({
      claims: {
        runtime: 'gnosis-uring',
        audience: 'did:key:z6MkAudience',
        subject: 'did:key:z6MkGuest',
        buildHash: 'build-hash-v3',
        hostCapabilities: ['auth.ucan', 'net.tcp.client'],
        admittedOperations: ['stream.open', 'stream.read', 'stream.write'],
        surfaces: ['wasm'],
        nonce: `nonce-${crypto.randomUUID()}`,
        issuedAt: nowMs - 1_000,
        expiresAt: nowMs + 60_000,
        policy,
        tee: {
          provider: 'mock',
          measurement: 'TEE-MEASUREMENT-3',
          tcbVersion: '1.2.0',
        },
      },
      privateKey: signingMaterial.privateKey,
      publicKey: signingMaterial.publicKey,
      keyId: 'runtime-replay',
    });

    const firstPass = await verifyCertifiedRuntimeAttestation(runtime, {
      nowMs,
      trustedKeyById: {
        'runtime-replay': signingMaterial.publicKey,
      },
      trustedMeasurements: ['TEE-MEASUREMENT-3'],
      nonceStore,
    });
    expect(firstPass.valid).toBe(true);

    const secondPass = await verifyCertifiedRuntimeAttestation(runtime, {
      nowMs: nowMs + 1,
      trustedKeyById: {
        'runtime-replay': signingMaterial.publicKey,
      },
      trustedMeasurements: ['TEE-MEASUREMENT-3'],
      nonceStore,
    });
    expect(secondPass.valid).toBe(false);
    expect(secondPass.reason).toContain('Nonce replay');

    const handleGrantClaims: ReactorHandleGrantClaims = {
      handleId: 'stream-1',
      kind: 'stream',
      ownerDid: 'did:key:z6MkGuest',
      audience: 'did:key:z6MkGuest',
      resource: 'aeon://stream/outbound/api.example.com:443/conn-1',
      operations: ['stream.read', 'stream.write', 'stream.close'],
      ucanCapabilities: ['aeon/stream.open', 'aeon/stream.write'],
      runtimeBindingHash: runtime.claims.bindingHash,
      delegationChainHash: 'bafydelegation',
      issuedAt: nowMs - 500,
      expiresAt: nowMs + 30_000,
    };

    const handleGrant = await createReactorHandleGrant({
      claims: handleGrantClaims,
      privateKey: signingMaterial.privateKey,
      publicKey: signingMaterial.publicKey,
      keyId: 'runtime-replay',
    });

    const verifiedGrant = await verifyReactorHandleGrant(handleGrant, {
      nowMs,
      trustedKeyById: {
        'runtime-replay': signingMaterial.publicKey,
      },
      expectedOwnerDid: 'did:key:z6MkGuest',
      expectedAudience: 'did:key:z6MkGuest',
      expectedOperation: 'stream.write',
      expectedUcanCapability: 'aeon/stream.write',
      expectedRuntimeBindingHash: runtime.claims.bindingHash,
      expectedDelegationChainHash: 'bafydelegation',
    });

    expect(verifiedGrant.valid).toBe(true);
    expect(verifiedGrant.claims?.handleId).toBe('stream-1');
  });
});
